// src/pages/Upload.js
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Upload.css';

const Upload = () => {
  const navigate = useNavigate();
  
  const [user, setUser] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [courses, setCourses] = useState([]);
  const [loadingCourses, setLoadingCourses] = useState(false);
  
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    course_id: '',
    type: 'notes'
  });

  const materialTypes = [
    { value: 'notes', label: '📄 Notes' },
    { value: 'pyq', label: '📝 Previous Year Questions (PYQ)' },
    { value: 'syllabus', label: '📋 Syllabus' },
    { value: 'lab', label: '🔬 Lab Manuals' },
    { value: 'assignment', label: '📝 Assignments' },
    { value: 'presentation', label: '📊 Presentations' },
    { value: 'important', label: '❓ Important Questions' },
    { value: 'book', label: '📚 Reference Books' }
  ];

  useEffect(() => {
    const savedUser = localStorage.getItem('study_portal_user');
    const savedToken = localStorage.getItem('study_portal_token');
    
    if (savedUser && savedToken) {
      try {
        const userData = JSON.parse(savedUser);
        setUser(userData);
        setIsAuthenticated(true);
      } catch (error) {
        console.error('Error parsing user:', error);
        navigate('/login');
      }
    } else {
      navigate('/login');
    }
    
    fetchCourses();
  }, [navigate]);

  const fetchCourses = async () => {
    try {
      setLoadingCourses(true);
      const response = await fetch('http://localhost:5000/api/courses');
      
      if (!response.ok) {
        throw new Error('Failed to fetch courses');
      }
      
      const data = await response.json();
      console.log('Courses from API:', data.courses);
      setCourses(data.courses || []);
      
    } catch (error) {
      console.error('Error fetching courses:', error);
      setCourses([]);
    } finally {
      setLoadingCourses(false);
    }
  };

  const handleAddSampleCourses = async () => {
    try {
      setLoadingCourses(true);
      const response = await fetch('http://localhost:5000/api/add-courses-public', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
      });
      
      const data = await response.json();
      
      if (response.ok) {
        alert(`✅ ${data.message || 'Courses added successfully!'}`);
        fetchCourses();
      } else {
        alert(`❌ ${data.error || 'Failed to add courses'}`);
      }
    } catch (error) {
      console.error('Error:', error);
      alert('❌ Network error. Check backend connection.');
    } finally {
      setLoadingCourses(false);
    }
  };

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile) {
      if (selectedFile.size > 10 * 1024 * 1024) {
        alert('❌ File size exceeds 10MB limit');
        e.target.value = '';
        return;
      }
      setFile(selectedFile);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  };

  const handleUpload = async () => {
    // Validation
    if (!file) {
      alert('❌ Please select a file');
      return;
    }
    if (!formData.title.trim()) {
      alert('❌ Please enter title');
      return;
    }
    if (!formData.course_id) {
      alert('❌ Please select a course');
      return;
    }

    setUploading(true);

    try {
      const token = localStorage.getItem('study_portal_token');
      
      if (!token) {
        throw new Error('Authentication token missing. Please login again.');
      }

      // ✅ FIX: Create FormData with correct field names
      const data = new FormData();
      data.append('file', file);
      data.append('title', formData.title);
      data.append('description', formData.description || '');
      data.append('course_id', parseInt(formData.course_id)); // ✅ Convert to integer
      data.append('type', formData.type);

      // Debug: Show FormData contents
      console.log('FormData contents:');
      for (let pair of data.entries()) {
        console.log(pair[0] + ':', pair[1]);
      }

      // Try with timeout
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 10000);

      const response = await fetch('http://localhost:5000/api/upload', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          // No Content-Type header for FormData
        },
        body: data,
        signal: controller.signal
      });

      clearTimeout(timeoutId);

      console.log('Response status:', response.status);
      
      let result;
      try {
        result = await response.json();
        console.log('Response data:', result);
      } catch (jsonError) {
        console.error('Error parsing JSON:', jsonError);
        throw new Error('Invalid response from server');
      }
      
      if (response.ok) {
        alert(`✅ ${result.message || 'File uploaded successfully!'}\n\nStatus: ${result.status || 'Pending approval'}`);
        
        // Reset form
        setFile(null);
        setFormData({
          title: '',
          description: '',
          course_id: '',
          type: 'notes'
        });
        document.getElementById('fileInput').value = '';
        
      } else {
        // Check for specific error messages
        let errorMsg = result.error || 'Server error';
        if (response.status === 422) {
          errorMsg = 'Validation error: Please check all fields are filled correctly';
        } else if (response.status === 401) {
          errorMsg = 'Session expired. Please login again.';
          localStorage.removeItem('study_portal_token');
          localStorage.removeItem('study_portal_user');
          navigate('/login');
        }
        alert(`❌ Upload failed: ${errorMsg}`);
      }
      
    } catch (error) {
      console.error('Upload error:', error);
      
      if (error.name === 'AbortError') {
        alert('❌ Request timeout. Server is taking too long to respond.');
      } else if (error.message.includes('NetworkError') || error.message.includes('Failed to fetch')) {
        alert('❌ Network error. Check if backend is running on http://localhost:5000');
      } else {
        alert(`❌ Upload failed: ${error.message}`);
      }
    } finally {
      setUploading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('study_portal_token');
    localStorage.removeItem('study_portal_user');
    window.location.href = '/';
  };

  // Show loading while checking authentication
  if (!user && isAuthenticated === false) {
    return (
      <div className="loading-container">
        <div>Loading authentication...</div>
      </div>
    );
  }

  return (
    <div className="upload-container">
      {/* Header with logout button */}
      <div className="upload-header-row">
        <header className="upload-header">
          <h1 className="upload-title">Upload Study Materials</h1>
          <p className="upload-subtitle">
            Share your notes, PYQs, and study materials
          </p>
        </header>
        
        <button onClick={handleLogout} className="logout-button">
          Logout
        </button>
      </div>

      {/* User Info */}
      <div className="user-info">
        <div className="user-avatar">
          {user?.name?.charAt(0)?.toUpperCase() || 'U'}
        </div>
        <div className="user-details">
          <p className="user-name">
            Uploading as: <span>{user?.name || 'User'}</span>
          </p>
          <p className="user-meta">
            {user?.branch || 'Branch'} • Semester {user?.semester || 'Semester'} • {user?.email || 'Email'}
          </p>
        </div>
      </div>

      {/* Debug Info (Remove in production) */}
      <div style={{ 
        background: '#f3f4f6', 
        padding: '0.5rem', 
        borderRadius: '8px', 
        marginBottom: '1rem',
        fontSize: '0.8rem',
        color: '#6b7280'
      }}>
        <p>Debug: Courses loaded: {courses.length} | User: {user?.email}</p>
      </div>

      {/* Warning if no courses */}
      {courses.length === 0 && !loadingCourses && (
        <div className="warning-box">
          <h3 className="warning-title">⚠️ No Courses Found!</h3>
          <p className="warning-message">Add sample courses to continue uploading</p>
          <button 
            onClick={handleAddSampleCourses}
            className="add-courses-btn"
            disabled={loadingCourses}
          >
            {loadingCourses ? 'Adding...' : '➕ Add Sample Courses'}
          </button>
          <p className="warning-note">
            This adds 6 sample courses (Data Structures, Digital Electronics, etc.)
          </p>
        </div>
      )}

      {/* File Upload Section */}
      <div className="upload-box">
        <input
          type="file"
          id="fileInput"
          className="file-input"
          onChange={handleFileChange}
          accept=".pdf,.doc,.docx,.ppt,.pptx,.txt,.jpg,.jpeg,.png"
          disabled={courses.length === 0}
        />
        <label htmlFor="fileInput" className="upload-label">
          📁 Choose File to Upload
        </label>
        
        {file && (
          <div className="file-info">
            <p><strong>Selected:</strong> {file.name}</p>
            <p><strong>Size:</strong> {(file.size / 1024).toFixed(2)} KB</p>
            <p><strong>Type:</strong> {file.type}</p>
          </div>
        )}
        
        <p className="file-types">
          📎 Supported: PDF, DOC, DOCX, PPT, PPTX, TXT, JPG, JPEG, PNG
          <br />
          ⚠️ Maximum file size: 10MB
        </p>
      </div>

      {/* Upload Form */}
      <div className="upload-form">
        {/* Title */}
        <div className="form-group">
          <label className="form-label">
            Title <span className="required">*</span>
          </label>
          <input
            type="text"
            name="title"
            placeholder="Enter descriptive title (e.g., Data Structures Complete Notes)"
            value={formData.title}
            onChange={handleInputChange}
            className="form-input"
            disabled={courses.length === 0}
            required
          />
        </div>

        {/* Description */}
        <div className="form-group">
          <label className="form-label">Description</label>
          <textarea
            name="description"
            placeholder="Add description about the material (optional)"
            value={formData.description}
            onChange={handleInputChange}
            className="form-textarea"
            disabled={courses.length === 0}
          />
        </div>

        {/* Course Dropdown */}
        <div className="form-group">
          <label className="form-label">
            Course <span className="required">*</span>
          </label>
          {loadingCourses ? (
            <div className="loading-courses">
              ⏳ Loading courses...
            </div>
          ) : courses.length === 0 ? (
            <div className="no-courses">
              ⚠️ No courses available. Click "Add Sample Courses" above.
            </div>
          ) : (
            <select
              name="course_id"
              value={formData.course_id}
              onChange={handleInputChange}
              className="form-select"
              required
              disabled={courses.length === 0}
            >
              <option value="">-- Select a course --</option>
              {courses.map(course => (
                <option key={course.id} value={course.id}>
                  {course.name} ({course.branch} - Sem {course.semester}) {course.code ? `[${course.code}]` : ''}
                </option>
              ))}
            </select>
          )}
        </div>

        {/* Type */}
        <div className="form-group">
          <label className="form-label">
            Type <span className="required">*</span>
          </label>
          <select
            name="type"
            value={formData.type}
            onChange={handleInputChange}
            className="form-select"
            disabled={courses.length === 0}
            required
          >
            {materialTypes.map(type => (
              <option key={type.value} value={type.value}>{type.label}</option>
            ))}
          </select>
        </div>

        {/* Upload Button */}
        <button
          onClick={handleUpload}
          disabled={uploading || courses.length === 0 || !file || !formData.title || !formData.course_id}
          className="upload-btn"
        >
          {uploading ? '⏳ Uploading...' : '📤 Upload Material'}
        </button>

        <div className="admin-note">
          <p className="admin-note-content">
            <span>⚠️</span>
            <span>
              <strong>Note:</strong> All uploads require admin approval. 
              Your file will be visible after review.
            </span>
          </p>
        </div>
      </div>
    </div>
  );
};

export default Upload;
